mapper.select:
SELECT sr.id, sr.order_id, sr.order_item_id, sr.product_id, sr.product_name, sr.quantity, sr.status, CASE sr.status WHEN 0 THEN '预占中' WHEN 1 THEN '已释放' WHEN 2 THEN '已扣减' END AS status_desc, sr.expire_time, sr.release_reason, sr.created_time, sr.updated_time FROM stock_reservation sr LEFT JOIN `order` o ON sr.order_id = o.id
AND sr.order_id = #{orderId}
AND sr.product_id = #{productId}
AND sr.status = #{status}
AND o.user_id = #{currentUserId}
ORDER BY sr.created_time DESC
